import{_ as e,c as t,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Функции платформы: Основные команды и управление навыками | OpenSkills","description":"Изучите функции платформы OpenSkills, освойте основные операции: команды, установку, просмотр, обновление и удаление навыков, поймите различия между глобальным и проектным управлением.","frontmatter":{"title":"Функции платформы: Основные команды и управление навыками | OpenSkills","sidebarTitle":"Освоение основных операций","subtitle":"Функции платформы: Основные команды и управление навыками | OpenSkills","description":"Изучите функции платформы OpenSkills, освойте основные операции: команды, установку, просмотр, обновление и удаление навыков, поймите различия между глобальным и проектным управлением.","order":2},"headers":[],"relativePath":"ru/numman-ali/openskills/platforms/index.md","filePath":"ru/numman-ali/openskills/platforms/index.md"}'),s={name:"ru/numman-ali/openskills/platforms/index.md"};function i(o,a,d,n,h,c){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="функции-платформы" tabindex="-1">Функции платформы <a class="header-anchor" href="#функции-платформы" aria-label="Permalink to &quot;Функции платформы&quot;">​</a></h1><p>В этом разделе подробно рассматриваются основные команды и функции управления навыками OpenSkills CLI, помогая вам перейти от базового использования к мастерству.</p><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Перед началом убедитесь</p><p>Прежде чем приступить к изучению этого раздела, убедитесь, что вы завершили раздел <a href="./../start/">Быстрый старт</a>, в частности:</p><ul><li><a href="./../start/installation/">Установка OpenSkills</a>: OpenSkills CLI успешно установлен</li><li><a href="./../start/first-skill/">Установка первого навыка</a>: Вы понимаете базовый процесс установки навыков</li></ul></div><h2 id="содержание-раздела" tabindex="-1">Содержание раздела <a class="header-anchor" href="#содержание-раздела" aria-label="Permalink to &quot;Содержание раздела&quot;">​</a></h2><p>Этот раздел включает 6 тем, охватывающих все основные функции OpenSkills:</p><h3 id="подробное-описание-команд" tabindex="-1"><a href="./cli-commands/">Подробное описание команд</a> <a class="header-anchor" href="#подробное-описание-команд" aria-label="Permalink to &quot;[Подробное описание команд](./cli-commands/)&quot;">​</a></h3><p>Полное описание всех 7 команд, параметров и флагов с краткой справочной таблицей. Подходит для пользователей, которым нужно быстро найти информацию об использовании команд.</p><h3 id="источники-установки" tabindex="-1"><a href="./install-sources/">Источники установки</a> <a class="header-anchor" href="#источники-установки" aria-label="Permalink to &quot;[Источники установки](./install-sources/)&quot;">​</a></h3><p>Подробное описание трёх источников установки: репозитории GitHub, локальные пути, приватные Git-репозитории. Сценарии применения, формат команд и важные замечания для каждого способа.</p><h3 id="глобальная-установка-vs-установка-в-проект" tabindex="-1"><a href="./global-vs-project/">Глобальная установка vs установка в проект</a> <a class="header-anchor" href="#глобальная-установка-vs-установка-в-проект" aria-label="Permalink to &quot;[Глобальная установка vs установка в проект](./global-vs-project/)&quot;">​</a></h3><p>Объяснение различий между установкой с флагом <code>--global</code> и установкой по умолчанию (в проект), помогающее выбрать подходящее место установки и понять правила приоритета поиска навыков.</p><h3 id="просмотр-установленных-навыков" tabindex="-1"><a href="./list-skills/">Просмотр установленных навыков</a> <a class="header-anchor" href="#просмотр-установленных-навыков" aria-label="Permalink to &quot;[Просмотр установленных навыков](./list-skills/)&quot;">​</a></h3><p>Научитесь использовать команду <code>list</code> для просмотра установленных навыков и понимать значение меток расположения <code>(project)</code> и <code>(global)</code>.</p><h3 id="обновление-навыков" tabindex="-1"><a href="./update-skills/">Обновление навыков</a> <a class="header-anchor" href="#обновление-навыков" aria-label="Permalink to &quot;[Обновление навыков](./update-skills/)&quot;">​</a></h3><p>Руководство по использованию команды <code>update</code> для обновления установленных навыков с поддержкой обновления всех навыков или выборочного обновления для синхронизации с исходным репозиторием.</p><h3 id="удаление-навыков" tabindex="-1"><a href="./remove-skills/">Удаление навыков</a> <a class="header-anchor" href="#удаление-навыков" aria-label="Permalink to &quot;[Удаление навыков](./remove-skills/)&quot;">​</a></h3><p>Описание двух способов удаления: интерактивная команда <code>manage</code> и скриптовая команда <code>remove</code> для эффективного управления библиотекой навыков.</p><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>Выберите подходящий путь обучения в зависимости от ваших потребностей:</p><h3 id="путь-a-систематическое-изучение-рекомендуется-для-новичков" tabindex="-1">Путь A: Систематическое изучение (рекомендуется для новичков) <a class="header-anchor" href="#путь-a-систематическое-изучение-рекомендуется-для-новичков" aria-label="Permalink to &quot;Путь A: Систематическое изучение (рекомендуется для новичков)&quot;">​</a></h3><p>Изучайте материал последовательно для формирования полной базы знаний:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Описание команд → Источники установки → Глобальная vs проектная → Просмотр навыков → Обновление навыков → Удаление навыков</span></span></code></pre></div><h3 id="путь-b-изучение-по-необходимости" tabindex="-1">Путь B: Изучение по необходимости <a class="header-anchor" href="#путь-b-изучение-по-необходимости" aria-label="Permalink to &quot;Путь B: Изучение по необходимости&quot;">​</a></h3><p>Переходите напрямую к нужной теме в зависимости от текущей задачи:</p><table tabindex="0"><thead><tr><th>Что вы хотите сделать</th><th>Читайте это</th></tr></thead><tbody><tr><td>Найти использование определённой команды</td><td><a href="./cli-commands/">Подробное описание команд</a></td></tr><tr><td>Установить навык из приватного репозитория</td><td><a href="./install-sources/">Источники установки</a></td></tr><tr><td>Решить, устанавливать глобально или в проект</td><td><a href="./global-vs-project/">Глобальная vs проектная</a></td></tr><tr><td>Посмотреть, какие навыки установлены</td><td><a href="./list-skills/">Просмотр установленных навыков</a></td></tr><tr><td>Обновить навык до последней версии</td><td><a href="./update-skills/">Обновление навыков</a></td></tr><tr><td>Очистить неиспользуемые навыки</td><td><a href="./remove-skills/">Удаление навыков</a></td></tr></tbody></table><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этого раздела вы освоите повседневное использование OpenSkills. Далее можно:</p><ul><li><strong><a href="./../advanced/">Продвинутые функции</a></strong>: Изучить режим Universal, настройку путей вывода, символические ссылки, создание собственных навыков и другие продвинутые возможности</li><li><strong><a href="./../faq/">Часто задаваемые вопросы</a></strong>: Обратиться к FAQ и руководству по устранению неполадок при возникновении проблем</li></ul>',29)])])}const b=e(s,[["render",i]]);export{u as __pageData,b as default};
